import{_ as s,o as e,c as p,ag as i}from"./chunks/framework.gU7RhlGX.js";const n="/Awesome-AI-Pedia/assets/image-1.K_2c_TSZ.png",t="/Awesome-AI-Pedia/assets/image-2.Dnpm9_Ck.png",o="data:image/png;base64,",r="/Awesome-AI-Pedia/assets/image-5.BG-F-rZR.png",l="/Awesome-AI-Pedia/assets/image-9.BfQ-qGfO.png",h="/Awesome-AI-Pedia/assets/image-10.DmACOP84.png",c="/Awesome-AI-Pedia/assets/image-11.DBvG1Mqv.png",g="/Awesome-AI-Pedia/assets/image-12.vRfTJxgC.png",d="/Awesome-AI-Pedia/assets/image-13.DWF93ukp.png",A="/Awesome-AI-Pedia/assets/image-14.D7QvF5Ul.png",m="/Awesome-AI-Pedia/assets/image-15.ClvxLfz6.png",f=JSON.parse('{"title":"openclaw安装教程：从零开始到接入飞书！","description":"","frontmatter":{},"headers":[],"relativePath":"openclaw/接入飞书.md","filePath":"openclaw/接入飞书.md","lastUpdated":1776422487000}'),b={name:"openclaw/接入飞书.md"};function u(k,a,w,B,I,y){return e(),p("div",null,[...a[0]||(a[0]=[i('<h1 id="openclaw安装教程-从零开始到接入飞书" tabindex="-1"><strong>openclaw安装教程：从零开始到接入飞书！</strong> <a class="header-anchor" href="#openclaw安装教程-从零开始到接入飞书" aria-label="Permalink to &quot;**openclaw安装教程：从零开始到接入飞书！**&quot;">​</a></h1><h2 id="开始安装" tabindex="-1"><strong>开始安装</strong> <a class="header-anchor" href="#开始安装" aria-label="Permalink to &quot;**开始安装**&quot;">​</a></h2><p>我这里教大家怎么装，以及如何接入飞书，让我们在国内也能玩起来。</p><p><strong>一定注意安全问题！</strong></p><p>这玩意权限很高，一定要悠着点。</p><p>如果你直接在主力机上跑，万一AI抽风执行个 <code>rm -rf /</code>，你电脑里的那资料可全完了。</p><hr><h2 id="第一步-安装openclaw" tabindex="-1"><strong>第一步：安装openclaw</strong> <a class="header-anchor" href="#第一步-安装openclaw" aria-label="Permalink to &quot;**第一步：安装openclaw**&quot;">​</a></h2><p>一行命令就行，很简单。</p><p>下面的命令适用于Mac、Windows和Linux。</p><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsSL </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//openclaw.ai/install.sh | bash</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>注意</strong>：运行前要先装Node.js，得22版本以上，否则会报错。</p><p>然后你就能看到它开始安装了。</p><p><img src="'+n+'" alt="安装过程"></p><p>安装好后，会出现这个：</p><p><img src="'+t+'" alt="安装确认"></p><p>问你选yes还是no。</p><p>意思就是：我懂这大龙虾能力很强但风险极大，你确认继续吗？</p><p>只有选yes，才让你进行下一步。</p><p>选yes后，会看到一个选项：</p><p><img src="'+o+'" alt="配置选项"></p><p>第一个是快速启动，后续通过 <code>openclaw configure</code> 配置信息。</p><p>第二个是先手动配置。</p><p>我们选第一个。</p><hr><h2 id="第二步-配置模型" tabindex="-1"><strong>第二步：配置模型</strong> <a class="header-anchor" href="#第二步-配置模型" aria-label="Permalink to &quot;**第二步：配置模型**&quot;">​</a></h2><p>然后它会让你配置模型。</p><p><img src="'+r+'" alt="模型配置"></p><p>你也可以选国产模型，比如MiniMax、Qwen、智谱。</p><p><strong>优势：</strong></p><ul><li>✅ 国内直连，无需魔法</li><li>✅ 价格便宜，比官方便宜50%-70%</li><li>✅ 支持支付宝、微信支付</li><li>✅ 支持Claude、GPT、Gemini等多种模型</li><li>✅ 24小时稳定运行</li></ul><p><strong>提醒一句</strong>：</p><p>这玩意上下文工程做得奇差无比。</p><p>烧Token的速度是你难以想象的离谱。</p><hr><h2 id="第三步-配置skills" tabindex="-1"><strong>第三步：配置Skills</strong> <a class="header-anchor" href="#第三步-配置skills" aria-label="Permalink to &quot;**第三步：配置Skills**&quot;">​</a></h2><p>每个后面都有描述，你可以挑喜欢的装。</p><p>懒得挑，直接跳过也行，后续跟它对话也能装。</p><hr><h2 id="第五步-配置hooks" tabindex="-1"><strong>第五步：配置Hooks</strong> <a class="header-anchor" href="#第五步-配置hooks" aria-label="Permalink to &quot;**第五步：配置Hooks**&quot;">​</a></h2><p>继续下一步，会问你要不要配置hooks。</p><p>可以理解为三个插件：</p><p><strong>boot-md</strong>：启动时自动加载一段markdown文本当默认引导内容。常用于把你的规则、偏好、项目背景在每次启动时塞进去。</p><p><strong>command-logger</strong>：把你在openclaw里执行过的命令和关键操作记一份日志，方便排查问题和复盘。如果你比较在意隐私或不想留痕，就别开它。</p><p><strong>session-memory</strong>：保存会话相关的状态或记忆，让它下次能延续上下文，体验会更连贯。</p><p>我建议都开，都非常实用。</p><hr><h2 id="第六步-启动openclaw" tabindex="-1"><strong>第六步：启动openclaw</strong> <a class="header-anchor" href="#第六步-启动openclaw" aria-label="Permalink to &quot;**第六步：启动openclaw**&quot;">​</a></h2><p>终于，一切就绪！</p><p>用这个命令启动：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw gateway --verbose</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>一般端口默认是18789，所以你可以直接访问：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://127.0.0.1:18789/chat</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后就能看到亲切的小龙虾界面了！</p><hr><h2 id="第七步-接入飞书-重点" tabindex="-1"><strong>第七步：接入飞书（重点！）</strong> <a class="header-anchor" href="#第七步-接入飞书-重点" aria-label="Permalink to &quot;**第七步：接入飞书（重点！）**&quot;">​</a></h2><p>我相信所有人，肯定都想在手机端或别的聊天软件里用。</p><p>这才是它最大的魅力。</p><p>在国内，现在最容易接进去的，就是飞书。</p><p>因为飞书的机器人，刚好跟这玩意非常吻合。</p><p>有个大佬做了飞书连接open的项目：</p><p><a href="https://github.com/m1heng/openclaw-feishu" target="_blank" rel="noreferrer">https://github.com/m1heng/openclaw-feishu</a></p><p>直接在WebUI输入：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>给我安装 openclaw plugins install @m1heng-clawd/feishu 这个命令</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="配置飞书机器人" tabindex="-1"><strong>配置飞书机器人</strong> <a class="header-anchor" href="#配置飞书机器人" aria-label="Permalink to &quot;**配置飞书机器人**&quot;">​</a></h2><p>它说装好后，还需要去飞书开放平台（open.feishu.cn）建个应用。</p><p>把App ID和App Secret记下来，接下来要用。</p><p><img src="'+l+'" alt="飞书开放平台"></p><p>然后最骚的操作来了...</p><p>你直接在对话框中发送自己的App ID和App Secret给它。</p><p>没错，它会自己看着办，把剩下的配置全给你搞定。</p><p><img src="'+h+'" alt="自动配置"></p><p>真的，爽到爆炸。</p><hr><h2 id="飞书开放平台设置" tabindex="-1"><strong>飞书开放平台设置</strong> <a class="header-anchor" href="#飞书开放平台设置" aria-label="Permalink to &quot;**飞书开放平台设置**&quot;">​</a></h2><p>然后就是飞书开放平台自己的一些设置了。</p><p>这个就不太好上AI了，而且也不复杂。</p><p>大家先把机器人加入进去：</p><p><img src="'+c+'" alt="添加机器人"></p><p>接下来开启一些必要的权限，GitHub中作者也有讲到：</p><p><img src="'+g+'" alt="权限配置1"></p><p><img src="'+d+'" alt="权限配置2"></p><p>然后，把下面这些也都配置上：</p><p><img src="'+A+'" alt="其他配置"></p><p>最后，一切大功告成！</p><p>然后你就进行发布：</p><p><img src="'+m+'" alt="发布应用"></p><p>就可以在飞书里面，跟它畅聊了。</p><hr><h2 id="实际使用体验" tabindex="-1"><strong>实际使用体验</strong> <a class="header-anchor" href="#实际使用体验" aria-label="Permalink to &quot;**实际使用体验**&quot;">​</a></h2><p>比如公司报销发票，需要把发票内容填进一个Excel表格模板里</p><p>现在，只需在飞书给它下个令。</p><p>它便会在后台一顿操作：</p><ul><li>打开本地文件</li><li>读取内容</li><li>自动填充Excel</li></ul><p>一眨眼的功夫，活儿干完了。</p><p>这台电脑我就一直放在那，也没打算关机。</p><p>晚上回了家，我还是可以用手机上飞书，来对它进行遥控。</p><p>还是相当好玩的。</p><hr>',100)])])}const v=s(b,[["render",u]]);export{f as __pageData,v as default};
